settings.cus_css:
.caqa-image-widh-text .image-with-text__grid{max-width:140rem;margin:0 auto;}
.caqa-image-widh-text .image-with-text__content,
 .caqa-image-widh-text .image-with-text__media{background: transparent;}
.caqa-image-widh-text{background-image: linear-gradient(-45deg, #004992 22%, #01850b 84%);max-width:100%;}
.caqa-image-widh-text .image-with-text__heading{color:#fff;}
.caqa-image-widh-text .image-with-text__text{color: #f0d204;font-size: 26px;letter-spacing: 1px;line-height: 31px;margin-top:5px;font-weight:500;}

@media screen and (max-width:990px){
.caqa-image-widh-textt .image-with-text__content{padding:20px 30px 20px;}
.caqa-image-widh-text .image-with-text__heading,
  .caqa-image-widh-text .image-with-text__text{font-size:23px;}
  } 

@media screen and (max-width:575px){
.caqa-image-widh-text .image-with-text__heading,
.caqa-image-widh-textt .image-with-text__text{font-size:18px;}
  }
